const readline = require('readline');
const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

const lines = [];
rl.on('line', (input) => {
  lines.push(input);
  if (lines.length === 3) {
    const person = {
      name: lines[0],
      age: parseInt(lines[1]),
      city: lines[2]
    };
    console.log(person.name);
    rl.close();
  }
});

