const readline = require('readline');
const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

rl.on('line', (input) => {
  const numbers = input.split(' ').map(Number);
  const result = numbers
    .filter(num => num % 2 === 0)
    .map(num => num * num);

  if (result.length === 0) {
    console.log(0);
  } else {
    console.log(result.join(' '));
  }
  rl.close();
});
